import { BrowserRouter, Route, Routes, Link, useLocation } from "react-router-dom";
import { useState, useEffect, useRef } from "react";
import { Provider, useSelector, useDispatch } from "react-redux";
import store, { toggleTheme, closeMobileMenu, toggleMobileMenu } from "./store/store";
import { useVisitor } from "./hooks/useApi";
import Index from "./Component/Index";
import About from "./Component/About";
import Timeline from "./Component/Timeline";
import Projects from "./Component/Projects";
import Skills from "./Component/Skills";
import ProjectModal from "./Component/ProjectModal";
import "./App.css";

function Navigation() {
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  const dispatch = useDispatch();
  const { mode } = useSelector((state) => state.theme);
  const { isMobileMenuOpen } = useSelector((state) => state.ui);
  const { count } = useSelector((state) => state.visitor);
  const navRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    dispatch(closeMobileMenu());
  }, [location, dispatch]);

  const navLinks = [
    { path: '/about', label: 'About' },
    { path: '/timeline', label: 'Timeline' },
    { path: '/projects', label: 'Projects' },
    { path: '/skills', label: 'Skills' },
  ];

  return (
      <nav ref={navRef} className={`nav ${scrolled ? 'nav-scrolled' : ''}`}>
        <div className="nav-container">
          <Link to="/" className="logo">
            <span className="logo-bracket">&lt;</span>
            KSL
            <span className="logo-bracket">/&gt;</span>
          </Link>

          <div className="nav-links">
            {navLinks.map((link) => (
                <Link
                    key={link.path}
                    to={link.path}
                    className={location.pathname === link.path ? 'active' : ''}
                >
                  {link.label}
                </Link>
            ))}
          </div>

          <div className="nav-controls">
          <span className="visitor-count">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
              <circle cx="9" cy="7" r="4"/>
              <path d="M23 21v-2a4 4 0 0 0-3-3.87"/>
              <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
            </svg>
            {count}
          </span>

            <button
                className="theme-toggle"
                onClick={() => dispatch(toggleTheme())}
                aria-label="Toggle theme"
            >
              {mode === 'light' ? (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/>
                  </svg>
              ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <circle cx="12" cy="12" r="5"/>
                    <line x1="12" y1="1" x2="12" y2="3"/>
                    <line x1="12" y1="21" x2="12" y2="23"/>
                    <line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/>
                    <line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/>
                    <line x1="1" y1="12" x2="3" y2="12"/>
                    <line x1="21" y1="12" x2="23" y2="12"/>
                    <line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/>
                    <line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/>
                  </svg>
              )}
            </button>

            <button
                className="mobile-menu-btn"
                onClick={() => dispatch(toggleMobileMenu())}
                aria-label="Toggle menu"
            >
            <span className={`hamburger ${isMobileMenuOpen ? 'open' : ''}`}>
              <span></span>
              <span></span>
              <span></span>
            </span>
            </button>
          </div>
        </div>

        <div className={`mobile-nav ${isMobileMenuOpen ? 'open' : ''}`}>
          {navLinks.map((link) => (
              <Link
                  key={link.path}
                  to={link.path}
                  className={location.pathname === link.path ? 'active' : ''}
              >
                {link.label}
              </Link>
          ))}
        </div>
      </nav>
  );
}

